com.mirth.connect.plugins.javascriptstep.script:
var mapping;

try {
	var datetime = msg['PV1']['PV1.44']['PV1.44.1'].toString();
	mapping = datetime.substring(0, 4) + '-' + datetime.substring(4, 6) + '-' + datetime.substring(6, 8);
} catch (e) {
	logger.error(e);
	mapping = '';
}

channelMap.put('VisitDate', validate(mapping, '', new Array()));

var mapping;

try {
	var datetime = msg['PV1']['PV1.44']['PV1.44.1'].toString();
	mapping = datetime.substring(8, 10) + ':' + datetime.substring(10, 12);

	if (mapping == ':') {
		mapping = '00:00';
	}

} catch (e) {
	logger.error(e);
	mapping = '';
}

channelMap.put('VisitTime', validate(mapping, '', new Array()));

var mapping;

try {
	var messagetype = msg['MSH']['MSH.9']['MSH.9.2'].toString();
	mapping = (messagetype == 'A31') ? '1' : '0';
} catch (e) {
	logger.error(e);
	mapping = '';
}

channelMap.put('UpdateOnly', validate(mapping, '', new Array()));

var mapping;

try {
	var eventtime = msg['EVN']['EVN.2']['EVN.2.1'].toString();

	var messagetype = msg['MSH']['MSH.1']['MSH.1.1'].toString();

	var visitstatus = 'Scheduled';

	if (messagetype == 'A01') {
		visitstatus = 'Attended';

	}  else if (messagetype == 'A03') {
		visitstatus = 'Discharged ';
	}


     mapping = '<AppointmentMapping><Key>Status</Key><Value>' + visitstatus + '</Value></AppointmentMapping>';

	if (messagetype == 'A08') {
		mapping = '';
	}

} catch (e) {
	logger.error(e);
	mapping = '';
}

channelMap.put('VisitStatusXML', validate(mapping, '', new Array()));

var ResponseXML = new XML(response.getMessage().toString());

logger.debug("ResponseXML: " + ResponseXML.toString());
logger.debug("Warning count: " + ResponseXML.Warnings.children().length());

for each (var w in ResponseXML.Warnings.children()) {
	logger.debug("Warning: " + w.toString());

	responseStatus = ERROR;

	if (responseErrorMessage == null) {
		responseErrorMessage = w.toString();
	} else {
		responseErrorMessage += "\n" + w.toString();
	}
}

var ResponseXML = new XML(response.getMessage().toString());

logger.debug("ResponseXML: " + ResponseXML.toString());

channelMap.put('PatientId', validate( ResponseXML.Id.toString() , '', new Array()));

channel.postprocessingScript:
// This script executes once after a message has been processed
// Responses returned from here will be stored as "Postprocessor" in the response map
return;

channel.deployScript:
// This script executes once when the channel is deployed
// You only have access to the globalMap and globalChannelMap here to persist data
return;

channel.undeployScript:
// This script executes once when the channel is undeployed
// You only have access to the globalMap and globalChannelMap here to persist data
return;
